CustomField.formula:
IF(
    AND(
        OR(
            UPPER(TEXT(sugati__SB_Opportunity__r.StageName)) == UPPER($Setup.sugati__Sugati_Stage_Name_Mapping__c.sugati__Booked__c), 
            AND(sugati__SB_Opportunity__r.IsClosed, sugati__SB_Opportunity__r.IsWon)
        ),
        CONTAINS($Setup.sugati__Supplier_Voucher_Setting__c.sugati__Accommodation_Component_Lists__c + $Setup.sugati__Supplier_Voucher_Setting__c.sugati__Activity_Component_Lists__c +  $Setup.sugati__Supplier_Voucher_Setting__c.sugati__Transportation_Component_Lists__c + $Setup.sugati__Supplier_Voucher_Setting__c.sugati__Flight_Component_Lists__c, RecordType.Name)
    ), 
    HYPERLINK(LEFT($Api.Partner_Server_URL_260, FIND( '/services', $Api.Partner_Server_URL_260)) + 'apex/' + $Setup.sugati__Site__c.sugati__Namespace__c + 'SupplierVouchers?id=' + sugati__SB_Opportunity__r.Id + '&sbid=' + Id, sugati__SB_Opportunity__r.Name, '_blank'
    ), 
    ''
)
